// Creates mop_kb collection + 9 keyword payload indexes if absent.
// Idempotent: GET first, PUT only on 404.

const http = require('http');

const QDRANT_HOST = 'qdrant';
const QDRANT_PORT = 6333;
const QDRANT_KEY  = process.env.QDRANT_API_KEY || '';
const COLLECTION  = 'mop_kb';

function qdrantReq(method, path, body) {
  return new Promise((resolve, reject) => {
    const data = body ? JSON.stringify(body) : null;
    const headers = { 'Content-Type': 'application/json', 'api-key': QDRANT_KEY };
    if (data) headers['Content-Length'] = Buffer.byteLength(data);
    const req = http.request(
      { hostname: QDRANT_HOST, port: QDRANT_PORT, path, method },
      (res) => {
        const chunks = [];
        res.on('data', c => chunks.push(c));
        res.on('end', () => {
          const text = Buffer.concat(chunks).toString();
          try { resolve({ status: res.statusCode, data: JSON.parse(text) }); }
          catch (e) { resolve({ status: res.statusCode, data: text }); }
        });
      }
    );
    req.on('error', reject);
    if (data) req.write(data);
    req.end();
  });
}

const check = await qdrantReq('GET', `/collections/${COLLECTION}`);

if (check.status !== 200) {
  const create = await qdrantReq('PUT', `/collections/${COLLECTION}`, {
    vectors: { size: 768, distance: 'Cosine' },
  });
  if (create.status !== 200) {
    throw new Error('mop_kb creation failed: ' + JSON.stringify(create.data).slice(0, 300));
  }

  // 9 keyword payload indexes (mirror of memory_v1)
  const INDEXES = ['doc_kind', 'repo', 'host_origin', 'source_kind', 'severity', 'category', 'phase', 'topic', 'tags'];
  for (const field of INDEXES) {
    const r = await qdrantReq('PUT', `/collections/${COLLECTION}/index`, {
      field_name: field,
      field_schema: 'keyword',
    });
    if (r.status !== 200) {
      throw new Error(`Index creation failed for ${field}: ${JSON.stringify(r.data).slice(0, 200)}`);
    }
  }
}

// Pass through
return $input.all().map(item => ({ json: item.json, binary: item.binary }));

// For each uploaded PDF:
//   1. Call LiteLLM mop-ingest (Gemini 2.5 Pro multimodal) → structured markdown
//   2. Chunk markdown (header-split + paragraph, 1600 chars, 200 overlap)
//   3. Embed chunks in batches via mop-embed (text-embedding-004, 768 dims)
//   4. Delete old points for same filename+namespace, upsert new batch to mop_kb
// Architecture mirrors memory_v1 (25 payload fields, UUID from SHA256).

const http   = require('http');
const crypto = require('crypto');

const LITELLM_HOST = 'litellm';
const LITELLM_PORT = 4000;
const QDRANT_HOST  = 'qdrant';
const QDRANT_PORT  = 6333;
const COLLECTION   = 'mop_kb';
const LITELLM_KEY  = process.env.LITELLM_API_KEY || '';
const QDRANT_KEY   = process.env.QDRANT_API_KEY  || '';

function httpReq(host, port, method, path, body, extraHeaders) {
  return new Promise((resolve, reject) => {
    const data = body ? JSON.stringify(body) : null;
    const headers = { 'Content-Type': 'application/json', ...(extraHeaders || {}) };
    if (data) headers['Content-Length'] = Buffer.byteLength(data);
    const req = http.request({ hostname: host, port, path, method }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const text = Buffer.concat(chunks).toString();
        try { resolve({ status: res.statusCode, data: JSON.parse(text) }); }
        catch (e) { resolve({ status: res.statusCode, data: text }); }
      });
    });
    req.on('error', reject);
    if (data) req.write(data);
    req.end();
  });
}

function llm(path, body) {
  return httpReq(LITELLM_HOST, LITELLM_PORT, 'POST', path, body, { Authorization: `Bearer ${LITELLM_KEY}` });
}

function qdrant(method, path, body) {
  return httpReq(QDRANT_HOST, QDRANT_PORT, method, path, body, { 'api-key': QDRANT_KEY });
}

function sha256hex(s) {
  return crypto.createHash('sha256').update(s).digest('hex');
}

function toUUID(hex) {
  return [hex.slice(0,8), hex.slice(8,12), '4' + hex.slice(13,16), hex.slice(16,20), hex.slice(20,32)].join('-');
}

function chunkMarkdown(text) {
  const MAX = 1600, OVL = 200;
  const sections = text.split(/(?=\n#{1,3} )/);
  const chunks = [];
  for (const sec of sections) {
    if (!sec.trim()) continue;
    if (sec.length <= MAX) { chunks.push(sec.trim()); continue; }
    const paras = sec.split(/\n\n+/);
    let buf = '';
    for (const p of paras) {
      if (!p.trim()) continue;
      const candidate = buf ? buf + '\n\n' + p : p;
      if (candidate.length <= MAX) { buf = candidate; continue; }
      if (buf.trim()) chunks.push(buf.trim());
      if (p.length <= MAX) { buf = p; continue; }
      let s = p;
      while (s.length > MAX) { chunks.push(s.slice(0, MAX)); s = s.slice(MAX - OVL); }
      buf = s;
    }
    if (buf.trim()) chunks.push(buf.trim());
  }
  return chunks.filter(c => c.length >= 20);
}

function sectionHeader(chunk) {
  const m = chunk.match(/^#{1,3} (.+)/m);
  return m ? m[1].trim() : '';
}

// ── main ──────────────────────────────────────────────────────────────────────
const item     = $input.first();
const formData = item.json || {};
const binary   = item.binary || {};

const category  = String(formData.category  || 'sp');
const namespace = String(formData.namespace || 'mop').trim() || 'mop';
const language  = String(formData.language  || 'fr');
const indexedAt = new Date().toISOString();
const results   = [];

const files = Object.entries(binary)
  .filter(([, v]) => v && v.data)
  .map(([key, v]) => ({
    key,
    filename: v.fileName || key,
    mimeType: v.mimeType || 'application/pdf',
    base64: v.data,
  }));

if (files.length === 0) throw new Error('Aucun fichier trouvé dans le formulaire');

const INGEST_PROMPT = "Tu es un expert en systèmes télécom (DWDM, SDH, IP/MPLS). Extrais la totalité de ce document technique NOC en markdown structuré. Respecte la hiérarchie: H1 titre, H2 sections, H3 sous-sections. Tableaux en format markdown. Procédures en listes numérotées. Conserve tous les codes alarme, références SP et commandes CLI. Retourne UNIQUEMENT le markdown, sans préambule ni commentaire.";

for (const file of files) {
  // 1. LLM extraction (Gemini 2.5 Pro multimodal PDF)
  const llmResp = await llm('/v1/chat/completions', {
    model: 'mop-ingest',
    max_tokens: 8192,
    messages: [{ role: 'user', content: [
      { type: 'text', text: INGEST_PROMPT },
      { type: 'image_url', image_url: { url: `data:${file.mimeType};base64,${file.base64}` } },
    ]}],
  });
  if (llmResp.status !== 200) {
    throw new Error(`Extraction LLM échouée (${file.filename}): ` + JSON.stringify(llmResp.data).slice(0, 300));
  }
  const markdown   = llmResp.data.choices[0].message.content;
  const titleM     = markdown.match(/^#\s+(.+)/m);
  const docTitle   = titleM ? titleM[1].trim() : file.filename.replace(/\.pdf$/i, '');
  const contentHash = sha256hex(markdown);
  const refDocId   = sha256hex(`${namespace}:${file.filename}:${indexedAt}`);

  // 2. Chunk
  const chunks = chunkMarkdown(markdown);
  if (chunks.length === 0) throw new Error(`Aucun chunk produit pour ${file.filename}`);

  // 3. Delete old points (same filename + namespace = idempotent re-ingest)
  await qdrant('POST', `/collections/${COLLECTION}/points/delete`, {
    filter: { must: [
      { key: 'filename',  match: { value: file.filename } },
      { key: 'namespace', match: { value: namespace } },
    ]},
  });

  // 4. Embed in batches of 50
  const EMBED_BATCH = 50;
  const allVecs = [];
  for (let i = 0; i < chunks.length; i += EMBED_BATCH) {
    const batch = chunks.slice(i, i + EMBED_BATCH);
    const embResp = await llm('/v1/embeddings', { model: 'mop-embed', input: batch });
    if (embResp.status !== 200) {
      throw new Error('Embedding échoué: ' + JSON.stringify(embResp.data).slice(0, 300));
    }
    const sorted = [...embResp.data.data].sort((a, b) => a.index - b.index);
    allVecs.push(...sorted.map(e => e.embedding));
  }

  // 5. Build points (25 payload fields — memory_v1 schema)
  const points = chunks.map((chunk, idx) => ({
    id: toUUID(sha256hex(`${refDocId}:${idx}:${chunk.slice(0, 64)}`)),
    vector: allVecs[idx],
    payload: {
      schema_version:            '1.0',
      embedding_model:           'text-embedding-004',
      embedding_dim:             768,
      chunking_strategy_version: '1.0',
      ref_doc_id:                refDocId,
      repo:                      '',
      namespace,
      host_origin:               'sese-ai',
      source_kind:               'upload',
      doc_kind:                  category,
      topic:                     '',
      severity:                  '',
      category,
      phase:                     '',
      relative_path:             file.filename,
      filename:                  file.filename,
      language,
      tags:                      [],
      git_commit_sha:            '',
      content_hash:              contentHash,
      chunk_index:               idx,
      chunk_count:               chunks.length,
      chunking_kind:             'markdown_paragraph',
      section:                   sectionHeader(chunk),
      title:                     docTitle,
      indexed_at:                indexedAt,
      text:                      chunk,
    },
  }));

  // 6. Upsert in batches of 100
  const UPSERT_BATCH = 100;
  for (let i = 0; i < points.length; i += UPSERT_BATCH) {
    const r = await qdrant('PUT', `/collections/${COLLECTION}/points`, { points: points.slice(i, i + UPSERT_BATCH) });
    if (r.status !== 200) {
      throw new Error('Qdrant upsert échoué: ' + JSON.stringify(r.data).slice(0, 300));
    }
  }

  results.push({ filename: file.filename, chunks: chunks.length, ref_doc_id: refDocId });
}

return [{ json: {
  ok: true,
  files: results,
  total_chunks: results.reduce((s, r) => s + r.chunks, 0),
} }];
